import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreHeaderCase();

        assertNotNull(newFormat);
        assertTrue(newFormat.getIgnoreHeaderCase());
        // Original format should remain unchanged
        assertFalse(format.getIgnoreHeaderCase());

        // Calling again on the new instance returns a new instance with ignoreHeaderCase true
        CSVFormat newFormat2 = newFormat.withIgnoreHeaderCase();
        assertNotNull(newFormat2);
        assertTrue(newFormat2.getIgnoreHeaderCase());
        // The newFormat2 should be equal to newFormat (likely same instance or equal)
        assertEquals(newFormat, newFormat2);
    }
}
